import{_ as l,o as s,c as e,ag as o}from"./chunks/framework.f_9xDHrT.js";const u=JSON.parse('{"title":"认证流程","description":"获取 MissFisher 使用权、替换识别凭证，以及使用临时免验凭证。","frontmatter":{"title":"认证流程","description":"获取 MissFisher 使用权、替换识别凭证，以及使用临时免验凭证。"},"headers":[],"relativePath":"manual/auth.md","filePath":"manual/auth.md","lastUpdated":null}'),r={name:"manual/auth.md"};function a(t,i,c,d,n,h){return s(),e("div",null,[...i[0]||(i[0]=[o('<h2 id="完成认证以获得-missfisher-使用权" tabindex="-1">完成认证以获得 MissFisher 使用权 <a class="header-anchor" href="#完成认证以获得-missfisher-使用权" aria-label="Permalink to &quot;完成认证以获得 MissFisher 使用权&quot;">​</a></h2><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>认证完全免费。</p></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>MissFisher 开发者从未委托任何人在任何渠道以帮忙认证（验证）的理由收取费用。</p></div><h3 id="识别凭证" tabindex="-1">识别凭证 <a class="header-anchor" href="#识别凭证" aria-label="Permalink to &quot;识别凭证&quot;">​</a></h3><p>识别凭证会在 MissFisher 主界面的信息页中自动生成。</p><p><strong>识别凭证有两种：</strong></p><ul><li><strong>M 开头的设备识别凭证（机器码）</strong>：<br> 对应当前的设备信息。<br> 使用机器码认证后，任何角色都可在该设备上使用 MissFisher。</li><li><strong>S 开头的账号识别凭证（账号码）</strong>：<br> 对应当前登陆的账号。<br> 使用账号码认证后，该账号码对应账号下的任何角色都可使用 MissFisher。</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>设备识别凭证的变化：</strong></p><ul><li>在不同的设备上，会生成不同的设备识别凭证。</li><li>另外，设备信息变化时，也将导致设备识别凭证发生变化。 <ul><li>导致变化的常见情形：<br> 更换了不同的电脑<br> 更换了组成电脑的重要配件<br> 使用一些手段变更了配件在软件上的识别信息</li></ul></li></ul></div><h3 id="认证步骤" tabindex="-1">认证步骤 <a class="header-anchor" href="#认证步骤" aria-label="Permalink to &quot;认证步骤&quot;">​</a></h3><p><strong>前往 Discord：</strong></p><ol><li>在游戏中输入 <code>/mf</code> 以打开 MissFisher 主界面</li><li>点击 <code>信息</code> 页签以展开信息页</li><li>点击 <code>Discord</code> 按钮来前往 MissFisher 的 Discord 服务器</li><li>按指引接受邀请并登陆或注册 Discord</li></ol><p><strong>在 Discord 认证：</strong></p><ol><li>进入「点这里认证」频道</li><li>点击聊天输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/verify</code></li><li>回到游戏中 - 在 MissFisher 主界面的信息页中，点击想要认证的任一识别凭证以将其复制到剪贴板</li><li>将识别凭证粘贴到命令参数输入框中</li><li>发送并等待机器人确认</li></ol><h3 id="替换凭证" tabindex="-1">替换凭证 <a class="header-anchor" href="#替换凭证" aria-label="Permalink to &quot;替换凭证&quot;">​</a></h3><p>你可以在 MissFisher 的 Discord 服务器中的「点这里认证」频道中使用 <code>/replace</code> 命令来将旧凭证替换为新凭证：</p><p><strong>获取指引与旧凭证：</strong></p><ol><li>进入 MissFisher 的 Discord 服务器中的「点这里认证」频道</li><li>点击输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/replace</code></li><li>回到游戏中 - 在 MissFisher 主界面的信息页中，点击想要认证的任一识别凭证以将其复制到剪贴板</li><li>将识别凭证粘贴到命令参数输入框中 - 直接发送以获取指引</li></ol><p><strong>用新凭证替换旧凭证：</strong></p><ol><li>点击输入框左侧的 <code>＋</code></li><li>选择 使用APP</li><li>在命令列表中找到并点击 <code>/replace</code></li><li>将识别凭证粘贴到命令参数输入框中</li><li>点击补全列表中的 <code>old_cert_id</code></li><li>复制机器人回复的指引中想要替换掉的识别凭证 - 粘贴到第 2 个命令参数输入框中</li><li>发送并等待机器人响应</li></ol><h3 id="临时免验凭证" tabindex="-1">临时免验凭证 <a class="header-anchor" href="#临时免验凭证" aria-label="Permalink to &quot;临时免验凭证&quot;">​</a></h3><p>临时免验凭证是为了应对验证服务器的状态波动而准备的。 在发生验证服务器状态波动而导致服务断链时，作者会在 Discord 发布临时免验凭证（不能保证在波动后立刻发布）。</p><p>它会发布后数天内过期，且通常只适用于最新版本。</p><p><strong>使用临时免验凭证</strong></p><ol><li>在 Discord 的公告频道复制临时免验凭证</li><li>打开 MissFisher 主界面</li><li>粘贴在临时免验凭证的输入框内，通常会立刻生效</li></ol><hr>',25)])])}const b=l(r,[["render",a]]);export{u as __pageData,b as default};
